1	/** A cell's position on the infinite grid as [x, y] coordinates. */
2	export type Cell = [number, number];
3	
4	type CellKey = string;
5	
6	const toKey = ([x, y]: Cell): CellKey => `${x},${y}`;
7	
8	const fromKey = (key: CellKey): Cell => {
9	  const [x, y] = key.split(",");
10	  return [Number(x), Number(y)];
11	};
12	
13	/**
14	 * Computes the next generation of Conway's Game of Life from the
15	 * given set of currently live cells, returning the cells that are
16	 * alive in the following tick.
17	 */
18	export function nextGeneration(liveCells: Cell[]): Cell[] {
19	  const liveKeys = new Set(liveCells.map(toKey));
20	  const neighborCounts = countNeighbors(liveCells);
21	
22	  const survives = (key: CellKey, count: number) =>
23	    liveKeys.has(key) && (count === 2 || count === 3);
24	  const isBorn = (key: CellKey, count: number) =>
25	    !liveKeys.has(key) && count === 3;
26	
27	  const next: Cell[] = [];
28	  for (const [key, count] of neighborCounts) {
29	    if (survives(key, count) || isBorn(key, count)) {
30	      next.push(fromKey(key));
31	    }
32	  }
33	  return next;
34	}
35	
36	function countNeighbors(liveCells: Cell[]): Map<CellKey, number> {
37	  const counts = new Map<CellKey, number>();
38	  for (const [x, y] of liveCells) {
39	    for (let dx = -1; dx <= 1; dx++) {
40	      for (let dy = -1; dy <= 1; dy++) {
41	        if (dx === 0 && dy === 0) continue;
42	        const key = toKey([x + dx, y + dy]);
43	        counts.set(key, (counts.get(key) ?? 0) + 1);
44	      }
45	    }
46	  }
47	  return counts;
48	}
49

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("Rule 1: two adjacent live cells both die from underpopulation — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 2: live cell with 2 neighbors survives — blinker center (0,1) survives from [(0,0),(0,1),(0,2)]", () => {
15	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
16	    expect(result).toContainEqual([0, 1]);
17	  });
18	  it("Rule 3: live cell with 4 neighbors dies from overpopulation — center (1,1) dies in 3x3 with center filled", () => {
19	    const grid: Cell[] = [
20	      [0, 0], [1, 0], [2, 0],
21	      [0, 1], [1, 1], [2, 1],
22	      [0, 2], [1, 2], [2, 2],
23	    ];
24	    const result = nextGeneration(grid);
25	    expect(result).not.toContainEqual([1, 1]);
26	  });
27	  it("Rule 4: dead cell with exactly 3 neighbors becomes alive — (1,1) born from [(0,0),(1,0),(0,1)]", () => {
28	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
29	    expect(result).toContainEqual([1, 1]);
30	  });
31	  it("Block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] unchanged", () => {
32	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
33	    expect(nextGeneration(block).sort()).toEqual(block.slice().sort());
34	  });
35	  it.todo("Blinker oscillates — vertical [(0,0),(0,1),(0,2)] → horizontal [(-1,1),(0,1),(1,1)]");
36	  it.todo("handles negative coordinates — block at negative coords unchanged");
37	});
